import { type ReactNode, createContext, useContext } from "react";

export type SupportedLocale =
  | "de"
  | "de-AT"
  | "en-CA"
  | "en-GB"
  | "en-US"
  | "fr"
  | "it"
  | "nl";

export interface Config {
  locale: SupportedLocale;
}

const ConfigContext = createContext<Config | null>(null);

export interface ConfigProviderProps {
  children: ReactNode;
  config: Config;
}

const defaultConfig: Config = {
  locale: "en-US",
};

/**
 * Provides configuration context for design system components.
 *
 * @example
 * ```tsx
 * <ConfigProvider config={{ locale: "en-GB" }}>
 *   <App />
 * </ConfigProvider>
 * ```
 */
export function ConfigProvider({ children, config }: ConfigProviderProps) {
  return (
    <ConfigContext.Provider value={config}>{children}</ConfigContext.Provider>
  );
}

ConfigProvider.displayName = "ConfigProvider";

/**
 * Hook to access the configuration context.
 * Returns the config from ConfigProvider if available, otherwise falls back to en-US.
 *
 * @returns The configuration object
 *
 * @example
 * ```tsx
 * const config = useConfig();
 * const locale = config.locale;
 * ```
 */
export function useConfig(): Config {
  const context = useContext(ConfigContext);

  if (context) {
    return context;
  }

  if (typeof window !== "undefined") {
    console.warn(
      "ConfigProvider not found. Using default values: ",
      JSON.stringify(defaultConfig, null, 2)
    );
  }
  return defaultConfig;
}
